export type Category = 'resume' | 'bookkeeping' | 'invoice' | 'planner' | 'letters' | 'business' | 'education' | 'email';

export interface TemplateFile {
  label: string;
  format: 'docx' | 'xlsx' | 'pdf' | 'gdocs' | 'gsheets' | 'html';
  href: string;
}

export interface Template {
  slug: string;
  title: string;
  description: string;
  longDescription: string;
  icon: string;
  category: Category;
  tags: string[];
  files: TemplateFile[];
  etsyPrice: string;
  features: string[];
  available: boolean;
}

export const categories: { id: Category; title: string; description: string; icon: string }[] = [
  { id: 'resume', title: 'Resume & Cover Letter', description: 'ATS-friendly resumes for every industry and career stage.', icon: '📄' },
  { id: 'bookkeeping', title: 'Bookkeeping & Finance', description: 'Income, expenses, P&L, mileage, and niche-specific bookkeeping.', icon: '📊' },
  { id: 'invoice', title: 'Invoices & Quotes', description: 'Invoices, estimates, receipts, and quote templates for every trade.', icon: '🧾' },
  { id: 'planner', title: 'Planners & Trackers', description: 'Budgets, habits, weekly planners, content calendars, life trackers.', icon: '🗓️' },
  { id: 'letters', title: 'Letters & Contracts', description: 'Rental applications, simple contracts, NDAs, notices, offer letters.', icon: '✉️' },
  { id: 'business', title: 'Small Business Ops', description: 'Pricing, onboarding, SOWs, business plans, sales pipelines.', icon: '💼' },
  { id: 'education', title: 'Teachers & Students', description: 'Lesson plans, gradebooks, study planners, reading logs.', icon: '📚' },
  { id: 'email', title: 'Email Signatures', description: 'Professional email signatures for Gmail and Outlook. Copy-paste ready.', icon: '📧' },
];

const gdoc = (slug: string) => `https://docs.google.com/document/d/PLACEHOLDER_${slug}/copy`;
const gsheet = (slug: string) => `https://docs.google.com/spreadsheets/d/PLACEHOLDER_${slug}/copy`;

const docxFiles = (slug: string): TemplateFile[] => [
  { label: 'Open in Google Docs (make a copy)', format: 'gdocs', href: gdoc(slug) },
  { label: 'Download .docx', format: 'docx', href: `/files/${slug}.docx` },
];
const xlsxFiles = (slug: string): TemplateFile[] => [
  { label: 'Open in Google Sheets (make a copy)', format: 'gsheets', href: gsheet(slug) },
  { label: 'Download .xlsx', format: 'xlsx', href: `/files/${slug}.xlsx` },
];
const pdfFiles = (slug: string): TemplateFile[] => [
  { label: 'Open in Google Docs (make a copy)', format: 'gdocs', href: gdoc(slug) },
  { label: 'Download PDF', format: 'pdf', href: `/files/${slug}.pdf` },
];
const emailSigFiles = (slug: string): TemplateFile[] => [
  { label: 'Open in Google Docs (copy into Gmail/Outlook)', format: 'gdocs', href: gdoc(slug) },
  { label: 'Download .html', format: 'html', href: `/files/${slug}.html` },
];

const t = (
  slug: string,
  title: string,
  description: string,
  longDescription: string,
  icon: string,
  category: Category,
  tags: string[],
  files: TemplateFile[],
  etsyPrice: string,
  features: string[],
): Template => ({ slug, title, description, longDescription, icon, category, tags, files, etsyPrice, features, available: true });

