export const getTemplate = (slug: string) => templates.find((tt) => tt.slug === slug);
export const getTemplatesByCategory = (cat: Category) => templates.filter((tt) => tt.category === cat);
export const getCategory = (id: Category) => categories.find((c) => c.id === id);
